sql:
SELECT name, contact_phone
FROM sales_managers
WHERE manager_end_date IS NULL;

SELECT DISTINCT sales_manager_id
FROM sales_activities
WHERE strftime('%Y-%m', actual_close_date) = '2023-05' AND status = 'closed';

SELECT name
FROM sales_managers
WHERE manager_end_date IS NULL;

SELECT activity_type, COUNT(*) AS activity_count
FROM area_activities
GROUP BY activity_type;

SELECT COUNT(*) AS total_activities
FROM area_activities
WHERE branch_id = 1;

SELECT COUNT(*) AS total_operations_tasks
FROM operations_tasks
WHERE branch_id = 1;

SELECT name, MIN(manager_start_date) AS earliest_start_date
FROM sales_managers
GROUP BY name;

